import org.owasp.esapi.ESAPI;
import org.owasp.esapi.errors.EncodingException;

import java.util.Scanner;

public class SecureXSSExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        // Encode the user input to prevent XSS
        String encodedUserInput = "";
        try {
            encodedUserInput = ESAPI.encoder().encodeForHTML(userInput);
        } catch (EncodingException e) {
            System.err.println("Error encoding user input");
            e.printStackTrace();
            System.exit(1);
        }

        String welcomeMessage = "Welcome, " + encodedUserInput + "!";

        // Output sanitized message
        System.out.println("<div>" + welcomeMessage + "</div>");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
